/**
 * @summary Get previous month cash flow Sankey data (income streams → income → expense categories + savings)
 */
export type getPreviousMonthCashFlowResponse = {
  data: GetPreviousMonthCashFlow200;
  status: number;
}

export const getGetPreviousMonthCashFlowUrl = (params?: GetPreviousMonthCashFlowParams,) => {

  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value === null) {
      normalizedParams.append(key, 'null');
    } else if (value !== undefined) {
      normalizedParams.append(key, value.toString());
    }
  });

  return `/api/v1/transaction/getPreviousMonthCashFlow?${normalizedParams.toString()}`
}

export const getPreviousMonthCashFlow = async (params?: GetPreviousMonthCashFlowParams, options?: RequestInit): Promise<getPreviousMonthCashFlowResponse> => {
return customFetch<Promise<getPreviousMonthCashFlowResponse>>(getGetPreviousMonthCashFlowUrl(params),
  {      
    ...options,
    method: 'GET'
    
  }
);}


